async function handleKgUserPlaylists() {
  const session = await ensureKgDfid({ token: kgCookieToken(), userid: kgCookieUin(), dfid: kgCookieObject().dfid || '', platform: 'life' });
  if (!session.token || !session.userid) return { provider: 'kugou', loggedIn: false, playlists: [] };
  kgSession = Object.assign({}, kgSession, session);
  const headers = Object.assign({}, KG_HEADERS, { Cookie: kgSessionCookie(session) });
  const json = await requestJson(KG_RAW_API_BASE + '/user/playlist?userid=' + encodeURIComponent(session.userid) + '&page=1&pagesize=100&platform=life&timestamp=' + Date.now(), { headers });
  const lists = (json && json.data && (json.data.lists || json.data.info)) || [];
  return { provider: 'kugou', loggedIn: true, userId: session.userid, playlists: lists.map(function(pl) { return mapKgPlaylist(pl, 'mine'); }).filter(function(pl) { return pl.id; }) };
}
